import { useState, useEffect } from 'react';
import { Pencil, Trash2, PlusCircle, ChevronUp, ChevronDown } from 'lucide-react';
import { getBoards, adminCreateBoard, adminUpdateBoard, adminDeleteBoard } from '../../lib/api';
import AdminGuard from '../../components/layout/AdminGuard';
import type { Board } from '../../lib/types';

export default function AdminBoards() {
  const [boards, setBoards] = useState<Board[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [showCreate, setShowCreate] = useState(false);
  const [editing, setEditing] = useState<string | null>(null);
  const [msg, setMsg] = useState('');

  // New board form
  const [nName, setNName] = useState('');
  const [nSlug, setNSlug] = useState('');
  const [nDesc, setNDesc] = useState('');
  const [nEra, setNEra] = useState('');
  const [nIcon, setNIcon] = useState('');

  // Edit form
  const [eName, setEName] = useState('');
  const [eSlug, setESlug] = useState('');
  const [eDesc, setEDesc] = useState('');
  const [eEra, setEEra] = useState('');
  const [eIcon, setEIcon] = useState('');
  const [eOrder, setEOrder] = useState(0);

  async function load() {
    setIsLoading(true);
    setBoards(await getBoards());
    setIsLoading(false);
  }
  useEffect(() => { load(); }, []);

  const F = { padding: '4px 8px', borderRadius: 6, border: '1px solid var(--color-border)', outline: 'none', fontSize: 13, color: 'var(--color-text-primary)', backgroundColor: 'var(--color-card-bg)' };

  async function moveUp(idx: number) {
    if (idx === 0) return;
    const a = boards[idx];
    const b = boards[idx - 1];
    await adminUpdateBoard(a.id, { name: a.name, slug: a.slug, description: a.description, era_tag: a.era_tag, icon: a.icon, display_order: b.display_order });
    await adminUpdateBoard(b.id, { name: b.name, slug: b.slug, description: b.description, era_tag: b.era_tag, icon: b.icon, display_order: a.display_order });
    load();
  }

  async function moveDown(idx: number) {
    if (idx === boards.length - 1) return;
    const a = boards[idx];
    const b = boards[idx + 1];
    await adminUpdateBoard(a.id, { name: a.name, slug: a.slug, description: a.description, era_tag: a.era_tag, icon: a.icon, display_order: b.display_order });
    await adminUpdateBoard(b.id, { name: b.name, slug: b.slug, description: b.description, era_tag: b.era_tag, icon: b.icon, display_order: a.display_order });
    load();
  }

  return (
    <AdminGuard>
      <div className="max-w-[900px] mx-auto px-4 pt-[72px] pb-8">
        <div className="flex items-center justify-between mb-4">
          <div>
            <h1 className="text-xl font-bold">版块管理</h1>
            <p className="text-sm m-0" style={{ color: 'var(--color-text-secondary)' }}>{boards.length} 个版块</p>
          </div>
          <button onClick={() => setShowCreate(!showCreate)} className="flex items-center gap-1 px-3 py-1.5 rounded-lg text-xs font-medium text-white cursor-pointer border-none"
            style={{ backgroundColor: 'var(--color-primary)' }}>
            <PlusCircle size={14} /> 新建版块
          </button>
        </div>

        {showCreate && (
          <div className="rounded-lg p-4 mb-4 flex flex-wrap items-center gap-2" style={{ backgroundColor: 'var(--color-card-bg)', boxShadow: 'var(--shadow-card)' }}>
            <input placeholder="名称" value={nName} onChange={e => setNName(e.target.value)} style={F} />
            <input placeholder="slug" value={nSlug} onChange={e => setNSlug(e.target.value)} style={F} />
            <input placeholder="描述" value={nDesc} onChange={e => setNDesc(e.target.value)} style={F} />
            <input placeholder="时代标签" value={nEra} onChange={e => setNEra(e.target.value)} style={{...F, width: 80}} />
            <input placeholder="图标" value={nIcon} onChange={e => setNIcon(e.target.value)} style={{...F, width: 60}} />
            <button onClick={async () => {
              if (!nName || !nSlug) { setMsg('名称和 slug 必填'); return; }
              await adminCreateBoard({ name: nName, slug: nSlug, description: nDesc, era_tag: nEra, icon: nIcon || '' });
              setNName(''); setNSlug(''); setNDesc(''); setNEra(''); setNIcon(''); setShowCreate(false);
              load();
            }} className="px-3 py-1.5 rounded text-xs font-medium text-white bg-[var(--color-success)] border-none cursor-pointer">创建</button>
          </div>
        )}

        {msg && <p className="text-xs mb-3" style={{ color: 'var(--color-danger)' }}>{msg}</p>}

        {isLoading ? (
          <div className="text-center py-12" style={{ color: 'var(--color-text-muted)' }}>加载中...</div>
        ) : (
          <div className="flex flex-col gap-2">
            {boards.map((b, i) => (
              <div key={b.id} className="rounded-lg p-3 flex items-center gap-3" style={{ backgroundColor: 'var(--color-card-bg)', boxShadow: 'var(--shadow-card)' }}>
                {editing === b.id ? (
                  <div className="flex flex-1 items-center gap-2">
                    <input value={eName} onChange={e => setEName(e.target.value)} style={F} />
                    <input value={eSlug} onChange={e => setESlug(e.target.value)} style={{...F, width: 120}} />
                    <input value={eDesc} onChange={e => setEDesc(e.target.value)} style={{...F, width: 120}} />
                    <input value={eEra} onChange={e => setEEra(e.target.value)} style={{...F, width: 80}} />
                    <input value={eIcon} onChange={e => setEIcon(e.target.value)} style={{...F, width: 50}} />
                    <input type="number" value={eOrder} onChange={e => setEOrder(Number(e.target.value))} style={{...F, width: 50}} />
                    <button onClick={async () => {
                      await adminUpdateBoard(b.id, { name: eName, slug: eSlug, description: eDesc, era_tag: eEra, icon: eIcon, display_order: eOrder });
                      setEditing(null); load();
                    }} className="px-2 py-1 rounded text-xs font-medium text-white bg-[var(--color-success)] border-none cursor-pointer">保存</button>
                    <button onClick={() => setEditing(null)} className="px-2 py-1 rounded text-xs font-medium border-none cursor-pointer" style={{ color: 'var(--color-text-muted)' }}>取消</button>
                  </div>
                ) : (
                  <>
                    <div className="flex items-center gap-1 shrink-0">
                      <button onClick={() => moveUp(i)} className="p-0.5 rounded cursor-pointer border-none bg-transparent hover:bg-[var(--color-page-bg)]" style={{ color: 'var(--color-text-muted)' }}><ChevronUp size={14} /></button>
                      <button onClick={() => moveDown(i)} className="p-0.5 rounded cursor-pointer border-none bg-transparent hover:bg-[var(--color-page-bg)]" style={{ color: 'var(--color-text-muted)' }}><ChevronDown size={14} /></button>
                    </div>
                    <span className="text-lg">{b.icon || ''}</span>
                    <div className="flex-1 min-w-0">
                      <span className="text-sm font-semibold" style={{ color: 'var(--color-text-primary)' }}>{b.name}</span>
                      <span className="text-xs ml-2" style={{ color: 'var(--color-text-muted)' }}>/{b.slug} · {b.era_tag} · 顺序 {b.display_order}</span>
                    </div>
                    <button onClick={() => { setEditing(b.id); setEName(b.name); setESlug(b.slug); setEDesc(b.description); setEEra(b.era_tag); setEIcon(b.icon); setEOrder(b.display_order); }}
                      className="p-1.5 rounded cursor-pointer border-none bg-transparent hover:bg-[var(--color-page-bg)]" style={{ color: 'var(--color-text-secondary)' }}><Pencil size={14} /></button>
                    <button onClick={async () => { if (confirm('确定删除？')) { await adminDeleteBoard(b.id); load(); } }}
                      className="p-1.5 rounded cursor-pointer border-none bg-transparent hover:bg-[var(--color-page-bg)]" style={{ color: 'var(--color-danger)' }}><Trash2 size={14} /></button>
                  </>
                )}
              </div>
            ))}
          </div>
        )}
      </div>
    </AdminGuard>
  );
}

import { useState, useEffect } from 'react';
import { useParams, Link } from 'react-router-dom';
import { Save, ArrowLeft } from 'lucide-react';
import { adminGetAllCharacters, adminUpdateCharacter } from '../../lib/api';
import AdminGuard from '../../components/layout/AdminGuard';
import type { AICharacter } from '../../lib/types';

export default function CharacterEdit() {
  const { id } = useParams<{ id: string }>();
  const [char, setChar] = useState<(AICharacter & { username?: string }) | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [msg, setMsg] = useState('');

  // Editable fields
  const [bio, setBio] = useState('');
  const [personality, setPersonality] = useState('');
  const [comedy, setComedy] = useState('');
  const [style, setStyle] = useState('');
  const [active, setActive] = useState(true);

  useEffect(() => {
    adminGetAllCharacters().then((list) => {
      const found = list.find((c: any) => c.id === id);
      if (found) {
        setChar(found as any);
        setBio((found as any).bio || '');
        setPersonality(found.personality_prompt || '');
        setComedy(found.comedy_notes || '');
        setStyle(found.writing_style || '');
        setActive(found.is_active);
      }
      setIsLoading(false);
    });
  }, [id]);

  async function handleSave() {
    if (!char) return;
    setSaving(true);
    setMsg('');
    try {
      await adminUpdateCharacter(char.id, {
        personality_prompt: personality,
        comedy_notes: comedy,
        writing_style: style,
        is_active: active,
        bio,
      });
      setMsg('保存成功');
    } catch (err: any) {
      setMsg('保存失败: ' + (err.message || '未知错误'));
    }
    setSaving(false);
  }

  const FIELD_STYLE: React.CSSProperties = {
    width: '100%', padding: '8px 12px', borderRadius: 8, border: '1px solid var(--color-border)',
    outline: 'none', fontSize: 14, color: 'var(--color-text-primary)', backgroundColor: 'var(--color-card-bg)',
  };

  return (
    <AdminGuard>
      <div className="max-w-[800px] mx-auto px-4 pt-[72px] pb-8">
        <Link to="/admin/characters" className="flex items-center gap-1 text-sm no-underline mb-4 hover:underline" style={{ color: 'var(--color-text-secondary)' }}>
          <ArrowLeft size={14} /> 返回角色列表
        </Link>

        {isLoading ? (
          <div className="text-center py-12" style={{ color: 'var(--color-text-muted)' }}>加载中...</div>
        ) : !char ? (
          <div className="text-center py-12">角色未找到</div>
        ) : (
          <div className="flex flex-col gap-4">
            <div className="flex items-center justify-between">
              <h1 className="text-xl font-bold">编辑：{(char as any).username}</h1>
              <div className="flex items-center gap-3">
                <label className="flex items-center gap-1.5 text-sm cursor-pointer" style={{ color: 'var(--color-text-secondary)' }}>
                  <input type="checkbox" checked={active} onChange={e => setActive(e.target.checked)} />
                  启用
                </label>
                <button
                  onClick={handleSave}
                  disabled={saving}
                  className="flex items-center gap-1.5 px-4 py-2 rounded-lg text-sm font-medium text-white cursor-pointer border-none disabled:opacity-50 transition-colors"
                  style={{ backgroundColor: 'var(--color-primary)' }}
                >
                  <Save size={14} /> {saving ? '保存中...' : '保存'}
                </button>
              </div>
            </div>

            {msg && (
              <div className="text-sm px-3 py-2 rounded-lg" style={{
                backgroundColor: msg.includes('失败') ? '#FDEDED' : '#E8F5E9',
                color: msg.includes('失败') ? 'var(--color-danger)' : 'var(--color-success)',
              }}>{msg}</div>
            )}

            <div className="rounded-lg p-5 flex flex-col gap-4" style={{ backgroundColor: 'var(--color-card-bg)', boxShadow: 'var(--shadow-card)' }}>
              <div>
                <label className="block text-sm font-medium mb-1">简介 (bio)</label>
                <textarea rows={3} value={bio} onChange={e => setBio(e.target.value)} style={FIELD_STYLE} />
              </div>

              <div>
                <label className="block text-sm font-medium mb-1">人格提示词 (personality_prompt)</label>
                <textarea rows={5} value={personality} onChange={e => setPersonality(e.target.value)} style={FIELD_STYLE} />
              </div>

              <div>
                <label className="block text-sm font-medium mb-1">喜剧方向 (comedy_notes)</label>
                <textarea rows={4} value={comedy} onChange={e => setComedy(e.target.value)} style={FIELD_STYLE} />
              </div>

              <div>
                <label className="block text-sm font-medium mb-1">语言风格 (writing_style)</label>
                <textarea rows={3} value={style} onChange={e => setStyle(e.target.value)} style={FIELD_STYLE} />
              </div>

            </div>
          </div>
        )}
      </div>
    </AdminGuard>
  );
}

import { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { Pencil, UserCheck, PlusCircle, Trash2 } from 'lucide-react';
import { adminGetAllCharacters, adminCreateCharacter, adminDeleteCharacter } from '../../lib/api';
import { useAuth } from '../../lib/auth';
import AdminGuard from '../../components/layout/AdminGuard';
import Avatar from '../../components/ui/Avatar';
import Badge from '../../components/ui/Badge';
import type { AICharacter } from '../../lib/types';

export default function AdminCharacters() {
  const { startImpersonation } = useAuth();
  const [characters, setCharacters] = useState<AICharacter[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [showCreate, setShowCreate] = useState(false);
  const [newChar, setNewChar] = useState({ username: '', era: '', birth_year: '', death_year: '', tags: '', personality: '', comedy: '', style: '' });
  const [createMsg, setCreateMsg] = useState('');

  useEffect(() => {
    adminGetAllCharacters().then(setCharacters).finally(() => setIsLoading(false));
  }, []);

  return (
    <AdminGuard>
      <div className="max-w-[900px] mx-auto px-4 pt-[72px] pb-8">
        <div className="flex items-center justify-between mb-2">
          <h1 className="text-xl font-bold">AI 角色管理</h1>
          <button
            onClick={() => setShowCreate(!showCreate)}
            className="flex items-center gap-1 px-3 py-1.5 rounded-lg text-xs font-medium text-white cursor-pointer border-none"
            style={{ backgroundColor: 'var(--color-primary)' }}
          >
            <PlusCircle size={14} /> 新建角色
          </button>
        </div>
        <p className="text-sm mb-6" style={{ color: 'var(--color-text-secondary)' }}>
          共 {characters.length} 个角色
        </p>

        {showCreate && (
          <div className="rounded-lg p-4 mb-4 flex flex-col gap-3" style={{ backgroundColor: 'var(--color-card-bg)', boxShadow: 'var(--shadow-card)' }}>
            <h3 className="text-sm font-bold m-0">新建 AI 角色</h3>
            <div className="grid grid-cols-3 gap-2">
              <input placeholder="用户名" value={newChar.username} onChange={e => setNewChar({...newChar, username: e.target.value})} className="px-2 py-1.5 rounded text-xs border outline-none bg-transparent" style={{ borderColor: 'var(--color-border)', color: 'var(--color-text-primary)' }} />
              <input placeholder="时代" value={newChar.era} onChange={e => setNewChar({...newChar, era: e.target.value})} className="px-2 py-1.5 rounded text-xs border outline-none bg-transparent" style={{ borderColor: 'var(--color-border)', color: 'var(--color-text-primary)' }} />
              <input placeholder="标签 (逗号分隔)" value={newChar.tags} onChange={e => setNewChar({...newChar, tags: e.target.value})} className="px-2 py-1.5 rounded text-xs border outline-none bg-transparent" style={{ borderColor: 'var(--color-border)', color: 'var(--color-text-primary)' }} />
              <input placeholder="生年" value={newChar.birth_year} onChange={e => setNewChar({...newChar, birth_year: e.target.value})} className="px-2 py-1.5 rounded text-xs border outline-none bg-transparent" style={{ borderColor: 'var(--color-border)', color: 'var(--color-text-primary)' }} />
              <input placeholder="卒年" value={newChar.death_year} onChange={e => setNewChar({...newChar, death_year: e.target.value})} className="px-2 py-1.5 rounded text-xs border outline-none bg-transparent" style={{ borderColor: 'var(--color-border)', color: 'var(--color-text-primary)' }} />
            </div>
            <textarea placeholder="人格提示词" value={newChar.personality} onChange={e => setNewChar({...newChar, personality: e.target.value})} rows={2} className="px-2 py-1.5 rounded text-xs border outline-none bg-transparent" style={{ borderColor: 'var(--color-border)', color: 'var(--color-text-primary)' }} />
            <textarea placeholder="喜剧方向" value={newChar.comedy} onChange={e => setNewChar({...newChar, comedy: e.target.value})} rows={2} className="px-2 py-1.5 rounded text-xs border outline-none bg-transparent" style={{ borderColor: 'var(--color-border)', color: 'var(--color-text-primary)' }} />
            <div className="flex items-center gap-3">
              <button onClick={async () => {
                setCreateMsg('');
                try {
                  await adminCreateCharacter({
                    username: newChar.username, era: newChar.era,
                    birth_year: parseInt(newChar.birth_year) || null,
                    death_year: parseInt(newChar.death_year) || null,
                    tags: newChar.tags.split(',').map(s => s.trim()).filter(Boolean),
                    personality: newChar.personality, comedy: newChar.comedy, style: newChar.style || '文言白话',
                  });
                  setShowCreate(false);
                  setNewChar({ username: '', era: '', birth_year: '', death_year: '', tags: '', personality: '', comedy: '', style: '' });
                  const list = await adminGetAllCharacters(); setCharacters(list);
                } catch (err: any) { setCreateMsg(err.message); }
              }} className="px-4 py-1.5 rounded text-xs font-medium text-white bg-[var(--color-primary)] border-none cursor-pointer">创建</button>
              {createMsg && <span className="text-xs" style={{ color: 'var(--color-danger)' }}>{createMsg}</span>}
            </div>
          </div>
        )}

        {isLoading ? (
          <div className="text-center py-12" style={{ color: 'var(--color-text-muted)' }}>加载中...</div>
        ) : (
          <div className="flex flex-col gap-3">
            {characters.map((c) => {
              return (
                <div
                  key={c.id}
                  className="rounded-lg p-4 flex items-center gap-4"
                  style={{ backgroundColor: 'var(--color-card-bg)', boxShadow: 'var(--shadow-card)' }}
                >
                  <Avatar name={(c as any).username || ''} url={(c as any).avatar_url} size={44} />
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-1.5 mb-0.5">
                      <span className="text-sm font-semibold" style={{ color: 'var(--color-text-primary)' }}>
                        {(c as any).username}
                      </span>
                      <Badge type="verified" />
                      {c.is_active ? (
                        <span className="text-xs px-1.5 py-0.5 rounded-full" style={{ backgroundColor: '#E8F5E9', color: 'var(--color-success)' }}>启用</span>
                      ) : (
                        <span className="text-xs px-1.5 py-0.5 rounded-full" style={{ backgroundColor: '#FFEBEE', color: 'var(--color-danger)' }}>禁用</span>
                      )}
                    </div>
                    <div className="text-xs" style={{ color: 'var(--color-text-muted)' }}>
                      {c.era}
                    </div>
                  </div>
                  <div className="flex items-center gap-1.5">
                    <button
                      onClick={() => startImpersonation({
                        profileId: c.id,
                        username: (c as any).username || '',
                        avatarUrl: (c as any).avatar_url || null,
                      })}
                      className="flex items-center gap-1 px-3 py-1.5 rounded-lg text-xs font-medium cursor-pointer border-none transition-colors"
                      style={{ backgroundColor: 'var(--color-success)', color: '#fff' }}
                    >
                      <UserCheck size={12} /> 以此身份发言
                    </button>
                    <Link
                      to={`/admin/characters/${c.id}`}
                      className="flex items-center gap-1 px-3 py-1.5 rounded-lg text-xs font-medium text-white no-underline transition-colors"
                      style={{ backgroundColor: 'var(--color-primary)' }}
                    >
                      <Pencil size={12} /> 编辑
                    </Link>
                    <button
                      onClick={async () => {
                        const name = (c as any).username || '';
                        if (!confirm(`确定删除角色「${name}」？`)) return;
                        await adminDeleteCharacter(c.id);
                        const list = await adminGetAllCharacters();
                        setCharacters(list);
                      }}
                      className="flex items-center gap-1 px-3 py-1.5 rounded-lg text-xs font-medium cursor-pointer border-none transition-colors"
                      style={{ backgroundColor: 'var(--color-danger)', color: '#fff' }}
                    >
                      <Trash2 size={12} /> 删除
                    </button>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>
    </AdminGuard>
  );
}

