import { useState, useEffect } from 'react';
import { ShieldOff } from 'lucide-react';
import { getBlockedIps, resetBlockedIp } from '../../lib/api';
import AdminGuard from '../../components/layout/AdminGuard';

interface BlockedIp {
  id: string;
  ip_address: string;
  reason: string | null;
  risk_score: number;
  blocked_until: string | null;
  created_at: string;
}

function timeAgo(d: string): string {
  const diff = Date.now() - new Date(d).getTime();
  const mins = Math.floor(diff / 60000);
  if (mins < 60) return `${mins}分钟前`;
  const hours = Math.floor(mins / 60);
  if (hours < 24) return `${hours}小时前`;
  return new Date(d).toLocaleDateString('zh-CN');
}

export default function IpRisks() {
  const [ips, setIps] = useState<BlockedIp[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [resetting, setResetting] = useState<string | null>(null);

  async function load() {
    setIsLoading(true);
    const data = await getBlockedIps();
    setIps(data as BlockedIp[]);
    setIsLoading(false);
  }

  useEffect(() => { load(); }, []);

  async function handleReset(ip: BlockedIp) {
    setResetting(ip.id);
    try {
      await resetBlockedIp(ip.id);
      await load();
    } catch { /* ignore */ }
    setResetting(null);
  }

  return (
    <AdminGuard>
      <div className="max-w-[900px] mx-auto px-4 pt-[72px] pb-8">
        <h1 className="text-xl font-bold mb-2">高风险 IP 与用户管理</h1>
        <p className="text-sm mb-6" style={{ color: 'var(--color-text-secondary)' }}>
          共 {ips.length} 个高风险条目
        </p>

        {isLoading ? (
          <div className="text-center py-12" style={{ color: 'var(--color-text-muted)' }}>加载中...</div>
        ) : ips.length === 0 ? (
          <div className="text-center py-12 text-sm" style={{ color: 'var(--color-text-muted)' }}>
            暂无高风险 IP
          </div>
        ) : (
          <div className="flex flex-col gap-2">
            {ips.map((ip) => (
              <div
                key={ip.id}
                className="rounded-lg p-4 flex items-center justify-between gap-4"
                style={{ backgroundColor: 'var(--color-card-bg)', boxShadow: 'var(--shadow-card)' }}
              >
                <div>
                  <div className="flex items-center gap-2 mb-1">
                    {ip.ip_address?.startsWith('user:') ? (
                      <span className="text-xs px-1.5 py-0.5 rounded-full" style={{ backgroundColor: '#E3F0FD', color: 'var(--color-primary)' }}>用户</span>
                    ) : (
                      <span className="text-xs px-1.5 py-0.5 rounded-full" style={{ backgroundColor: '#FFF3E0', color: '#E65100' }}>IP</span>
                    )}
                    <code className="text-sm font-mono" style={{ color: 'var(--color-text-primary)' }}>
                      {ip.ip_address?.replace('user:', '')}
                    </code>
                    <span
                      className="text-xs px-2 py-0.5 rounded-full font-medium"
                      style={{
                        backgroundColor: ip.risk_score >= 10 ? '#FDEDED' : '#FFF3E0',
                        color: ip.risk_score >= 10 ? 'var(--color-danger)' : '#E65100',
                      }}
                    >
                      风险 {ip.risk_score}
                    </span>
                  </div>
                  <div className="text-xs" style={{ color: 'var(--color-text-muted)' }}>
                    标记于 {timeAgo(ip.created_at)}
                    {ip.reason && <> · {ip.reason}</>}
                    {ip.blocked_until && <> · 封禁至 {new Date(ip.blocked_until).toLocaleString('zh-CN')}</>}
                  </div>
                </div>
                <button
                  onClick={() => handleReset(ip)}
                  disabled={resetting === ip.id}
                  className="flex items-center gap-1 px-3 py-1.5 rounded-lg text-xs font-medium text-white cursor-pointer border-none disabled:opacity-50 transition-colors"
                  style={{ backgroundColor: 'var(--color-primary)' }}
                >
                  <ShieldOff size={12} />
                  {resetting === ip.id ? '重置中...' : '重置'}
                </button>
              </div>
            ))}
          </div>
        )}
      </div>
    </AdminGuard>
  );
}

import { useState, useEffect } from 'react';
import { Check, X } from 'lucide-react';
import {
  getPendingThreads,
  getPendingPosts,
  approveThread,
  rejectThread,
  approvePost,
  rejectPost,
} from '../../lib/api';
import AdminGuard from '../../components/layout/AdminGuard';
import type { Thread, Post } from '../../lib/types';

function timeAgo(d: string): string {
  const diff = Date.now() - new Date(d).getTime();
  const mins = Math.floor(diff / 60000);
  if (mins < 60) return `${mins}分钟前`;
  const hours = Math.floor(mins / 60);
  if (hours < 24) return `${hours}小时前`;
  return new Date(d).toLocaleDateString('zh-CN');
}

export default function Moderation() {
  const [threads, setThreads] = useState<Thread[]>([]);
  const [posts, setPosts] = useState<Post[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [activeTab, setActiveTab] = useState<'threads' | 'posts'>('threads');
  const [acting, setActing] = useState<string | null>(null);

  async function load() {
    setIsLoading(true);
    const [t, p] = await Promise.all([getPendingThreads(), getPendingPosts()]);
    setThreads(t);
    setPosts(p);
    setIsLoading(false);
  }

  useEffect(() => { load(); }, []);

  const pendingCount = threads.length + posts.length;

  return (
    <AdminGuard>
      <div className="max-w-[900px] mx-auto px-4 pt-[72px] pb-8">
        <h1 className="text-xl font-bold mb-2">内容审核</h1>
        <p className="text-sm mb-6" style={{ color: 'var(--color-text-secondary)' }}>
          待审核：{pendingCount} 项
        </p>

        {/* Tabs */}
        <div className="flex gap-1 mb-4">
          <button
            onClick={() => setActiveTab('threads')}
            className="px-4 py-2 rounded-lg text-sm font-medium cursor-pointer border-none transition-colors"
            style={{
              backgroundColor: activeTab === 'threads' ? 'var(--color-primary)' : 'var(--color-card-bg)',
              color: activeTab === 'threads' ? '#fff' : 'var(--color-text-secondary)',
            }}
          >
            主题帖 ({threads.length})
          </button>
          <button
            onClick={() => setActiveTab('posts')}
            className="px-4 py-2 rounded-lg text-sm font-medium cursor-pointer border-none transition-colors"
            style={{
              backgroundColor: activeTab === 'posts' ? 'var(--color-primary)' : 'var(--color-card-bg)',
              color: activeTab === 'posts' ? '#fff' : 'var(--color-text-secondary)',
            }}
          >
            回复 ({posts.length})
          </button>
        </div>

        {isLoading ? (
          <div className="text-center py-12" style={{ color: 'var(--color-text-muted)' }}>加载中...</div>
        ) : activeTab === 'threads' ? (
          threads.length === 0 ? (
            <div className="text-center py-12 text-sm" style={{ color: 'var(--color-text-muted)' }}>暂无待审核帖子</div>
          ) : (
            <div className="flex flex-col gap-3">
              {threads.map((t) => (
                <div
                  key={t.id}
                  className="rounded-lg p-4"
                  style={{ backgroundColor: 'var(--color-card-bg)', boxShadow: 'var(--shadow-card)' }}
                >
                  <div className="flex items-start justify-between gap-4">
                    <div className="flex-1 min-w-0">
                      <h3 className="text-base font-bold mb-1">{t.title}</h3>
                      <p className="text-sm line-clamp-3 mb-2" style={{ color: 'var(--color-text-secondary)' }}>
                        {t.content.slice(0, 300)}
                      </p>
                      <div className="text-xs" style={{ color: 'var(--color-text-muted)' }}>
                        {timeAgo(t.created_at)}
                      </div>
                    </div>
                    <div className="flex items-center gap-2 shrink-0">
                      <button
                        onClick={async () => { setActing(t.id); await approveThread(t.id); setActing(null); load(); }}
                        disabled={acting === t.id}
                        className="flex items-center gap-1 px-3 py-1.5 rounded-lg text-xs font-medium text-white cursor-pointer border-none disabled:opacity-50"
                        style={{ backgroundColor: 'var(--color-success)' }}
                      >
                        <Check size={12} /> {acting === t.id ? '处理中' : '通过'}
                      </button>
                      <button
                        onClick={async () => { setActing(t.id); await rejectThread(t.id); setActing(null); load(); }}
                        disabled={acting === t.id}
                        className="flex items-center gap-1 px-3 py-1.5 rounded-lg text-xs font-medium text-white cursor-pointer border-none disabled:opacity-50"
                        style={{ backgroundColor: 'var(--color-danger)' }}
                      >
                        <X size={12} /> {acting === t.id ? '处理中' : '拒绝'}
                      </button>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )
        ) : (
          posts.length === 0 ? (
            <div className="text-center py-12 text-sm" style={{ color: 'var(--color-text-muted)' }}>暂无待审核回复</div>
          ) : (
            <div className="flex flex-col gap-3">
              {posts.map((p) => (
                <div
                  key={p.id}
                  className="rounded-lg p-4"
                  style={{ backgroundColor: 'var(--color-card-bg)', boxShadow: 'var(--shadow-card)' }}
                >
                  <div className="flex items-start justify-between gap-4">
                    <div className="flex-1 min-w-0">
                      <p className="text-sm mb-2" style={{ color: 'var(--color-text-secondary)' }}>
                        {p.content.slice(0, 300)}
                      </p>
                      <div className="text-xs" style={{ color: 'var(--color-text-muted)' }}>
                        {timeAgo(p.created_at)} · Thread: {p.thread_id.slice(0, 8)}…
                      </div>
                    </div>
                    <div className="flex items-center gap-2 shrink-0">
                      <button
                        onClick={async () => { setActing(p.id); await approvePost(p.id); setActing(null); load(); }}
                        disabled={acting === p.id}
                        className="flex items-center gap-1 px-3 py-1.5 rounded-lg text-xs font-medium text-white cursor-pointer border-none disabled:opacity-50"
                        style={{ backgroundColor: 'var(--color-success)' }}
                      >
                        <Check size={12} /> {acting === p.id ? '处理中' : '通过'}
                      </button>
                      <button
                        onClick={async () => { setActing(p.id); await rejectPost(p.id); setActing(null); load(); }}
                        disabled={acting === p.id}
                        className="flex items-center gap-1 px-3 py-1.5 rounded-lg text-xs font-medium text-white cursor-pointer border-none disabled:opacity-50"
                        style={{ backgroundColor: 'var(--color-danger)' }}
                      >
                        <X size={12} /> {acting === p.id ? '处理中' : '拒绝'}
                      </button>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )
        )}
      </div>
    </AdminGuard>
  );
}

import { useState, useEffect } from 'react';
import { adminGetDailyStats } from '../../lib/api';
import AdminGuard from '../../components/layout/AdminGuard';

export default function AdminStats() {
  const [stats, setStats] = useState<any[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    adminGetDailyStats(7).then(setStats).finally(() => setIsLoading(false));
  }, []);

  // Group by character
  const byChar: Record<string, any[]> = {};
  stats.forEach((s: any) => {
    const name = s.character_name || '未知';
    if (!byChar[name]) byChar[name] = [];
    byChar[name].push(s);
  });

  // Get unique dates
  const dates = [...new Set(stats.map((s: any) => s.date))].sort().reverse() as string[];

  // Colors
  const COLORS = ['#1877F2', '#42B72A', '#F02849', '#FF6900', '#8B5CF6', '#0EA5E9', '#EC4899', '#14B8A6'];

  return (
    <AdminGuard>
      <div className="max-w-[900px] mx-auto px-4 pt-[72px] pb-8">
        <h1 className="text-xl font-bold mb-6">AI 调用量统计</h1>

        {isLoading ? (
          <div className="text-center py-12" style={{ color: 'var(--color-text-muted)' }}>加载中...</div>
        ) : stats.length === 0 ? (
          <div className="text-center py-12 text-sm" style={{ color: 'var(--color-text-muted)' }}>暂无数据</div>
        ) : (
          <div>
            {/* Bar chart */}
            <div className="rounded-lg p-6 mb-6" style={{ backgroundColor: 'var(--color-card-bg)', boxShadow: 'var(--shadow-card)' }}>
              <h2 className="text-base font-bold mb-4">过去 7 天各角色回复数</h2>
              <div style={{ display: 'flex', alignItems: 'flex-end', gap: 4, height: 200, paddingBottom: 24 }}>
                {dates.map((date) => (
                  <div key={date} style={{ flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center', height: '100%', justifyContent: 'flex-end' }}>
                    {Object.entries(byChar).map(([name, items], ci) => {
                      const item = items.find((s: any) => s.date === date);
                      const count = item ? item.reply_count : 0;
                      const maxVal = Math.max(...stats.map((s: any) => s.reply_count), 1);
                      const h = maxVal > 0 ? (count / maxVal) * 160 : 0;
                      return (
                        <div
                          key={name}
                          title={`${name}: ${count}`}
                          style={{
                            width: 16, height: Math.max(h, count > 0 ? 4 : 1),
                            backgroundColor: count > 0 ? COLORS[ci % COLORS.length] : 'var(--color-border)',
                            borderRadius: '3px 3px 0 0',
                            transition: 'height 0.3s',
                          }}
                        />
                      );
                    })}
                    <span className="text-xs mt-2" style={{ color: 'var(--color-text-muted)', writingMode: 'vertical-rl', fontSize: 10 }}>
                      {date.slice(5)}
                    </span>
                  </div>
                ))}
              </div>
              {/* Legend */}
              <div className="flex flex-wrap gap-3 mt-4">
                {Object.keys(byChar).map((name, i) => (
                  <div key={name} className="flex items-center gap-1.5 text-xs" style={{ color: 'var(--color-text-secondary)' }}>
                    <span style={{ width: 10, height: 10, borderRadius: 2, backgroundColor: COLORS[i % COLORS.length], display: 'inline-block' }} />
                    {name}
                  </div>
                ))}
              </div>
            </div>

            {/* Table */}
            <div className="rounded-lg overflow-hidden" style={{ backgroundColor: 'var(--color-card-bg)', boxShadow: 'var(--shadow-card)' }}>
              <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 14 }}>
                <thead>
                  <tr style={{ borderBottom: '1px solid var(--color-border)' }}>
                    <th className="text-left px-4 py-3 text-sm font-semibold">日期</th>
                    {Object.keys(byChar).map(name => (
                      <th key={name} className="text-right px-4 py-3 text-sm font-semibold">{name}</th>
                    ))}
                    <th className="text-right px-4 py-3 text-sm font-semibold">合计</th>
                  </tr>
                </thead>
                <tbody>
                  {dates.map((date) => (
                    <tr key={date} style={{ borderBottom: '1px solid var(--color-border)' }}>
                      <td className="px-4 py-2.5 text-sm">{date}</td>
                      {Object.keys(byChar).map(name => {
                        const item = byChar[name].find((s: any) => s.date === date);
                        return (
                          <td key={name} className="text-right px-4 py-2.5 text-sm" style={{ color: 'var(--color-text-secondary)' }}>
                            {item ? item.reply_count : 0}
                          </td>
                        );
                      })}
                      <td className="text-right px-4 py-2.5 text-sm font-semibold">
                        {Object.values(byChar).reduce((sum, items) => {
                          const item = items.find((s: any) => s.date === date);
                          return sum + (item ? item.reply_count : 0);
                        }, 0)}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}
      </div>
    </AdminGuard>
  );
}

